const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

const trigger = $('Get Installation Token').first().json.body;
const taskData = $('Fetch Task Body').first().json;
const commentItems = $('Fetch Issue Comments').all().map(i => i.json);

const taskBody = taskData.body || trigger.issueBody || '';

const conversationHistory = commentItems.map(c => {
  const role = c.user?.type === 'Bot' ? 'assistant' : 'user';
  return { role, content: `**${c.user?.login}:** ${c.body}` };
});

const systemPrompt = `You are in an ongoing scoping conversation about this task in the Apeiron Cipher game project (Rust/Bevy ECS).

IMPORTANT: This is a TASK, not an epic. Keep the scope to a SINGLE pull request.

The task description has already been enriched with project-context references from the initial refinement pass. Use those references.

Respond to the human's latest comment. Be concise.

When the scope is becoming clear, propose a brief implementation plan. The human will apply the "sow_ready" label when satisfied.

If the scope is growing beyond a single PR, explicitly flag this — it may need to be converted to an epic.

Do NOT reference the full project-context in your response — the relevant parts are already in the task description.`;

const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'user', content: `Task: ${trigger.issueTitle}\n\n${taskBody}` },
  ...conversationHistory
];

return [{
  json: {
    messages,
    githubToken: $('Get Installation Token').first().json.githubToken,
    repoOwner: trigger.repoOwner,
    repoName: trigger.repoName,
    issueNumber: trigger.issueNumber
  }
}];

const llmResponse = $input.first().json;
const prev = $('Build Prompt').first().json;

const content = llmResponse.choices?.[0]?.message?.content || 'Error: No response from model.';

return [{
  json: {
    commentBody: content,
    githubToken: prev.githubToken,
    repoOwner: prev.repoOwner,
    repoName: prev.repoName,
    issueNumber: prev.issueNumber
  }
}];
